// Etape 2 : lancer L* avec un oracle d'equivalence par echantillonnage
var (learnedAbb, finalTableAbb, nEqAbb) = Lstar(ALPHABET, MqAbb,
    MakeSamplingEq(MqAbb, ALPHABET, 2000), verbose: false);

