Console.WriteLine($"  Conjectures (equivalences) : {nEqAbb}");
Console.WriteLine($"  |S| = {finalTableAbb.S.Count}, |E| = {finalTableAbb.E.Count}, MQ posees = {finalTableAbb.NMq}");

