def mine_rules(facts, min_support=2, min_conf=0.6):
    rels = defaultdict(set)
    for r, s, o in facts:
        rels[r].add((s, o))
    names = sorted(rels)
    candidates = []
    for h in names:                       # gabarit 1 : h(X,Y) :- b(X,Y)
        for b in names:
            if h == b:
                continue
            inst = rels[b]
            support = len(inst & rels[h])
            if support >= min_support:
                candidates.append({"kind": "impl", "head": h, "b1": b, "b2": None,
                                   "support": support, "conf": support / len(inst),
                                   "text": f"{h}(X,Y) :- {b}(X,Y)"})
    for h in names:                       # gabarit 2 : h(X,Y) :- b1(X,Z), b2(Z,Y)
        for b1 in names:
            for b2 in names:
                inst = {(x, y) for (x, z) in rels[b1]
                        for (z2, y) in rels[b2] if z == z2 and x != y}
                if not inst:
                    continue
                support = len(inst & rels[h])
                if support >= min_support:
                    candidates.append({"kind": "chain", "head": h, "b1": b1, "b2": b2,
                                       "support": support, "conf": support / len(inst),
                                       "text": f"{h}(X,Y) :- {b1}(X,Z), {b2}(Z,Y)"})
    return candidates, min_conf


candidates, MIN_CONF = mine_rules(kg_facts)
print(f"{'regle':<55} | support | conf | verdict")
print("-" * 85)
for c in sorted(candidates, key=lambda c: -c["conf"]):
    verdict = "RETENUE" if c["conf"] >= MIN_CONF else "rejetee"
    print(f"{c['text']:<55} |    {c['support']}    | {c['conf']:.2f} | {verdict}")
rules = [c for c in candidates if c["conf"] >= MIN_CONF]

def is_more_general_than(h1: Hypothesis, h2: Hypothesis) -> bool:
    """h1 est-elle plus generale que h2 ? (h1 >= h2)"""
    for i in range(len(ATTRIBUTES)):
        # h1[i] doit etre "?" ou egal a h2[i] pour chaque position
        if h1[i] != "?" and h1[i] != h2[i]:
            return False
    return True


def is_more_specific_than(h1: Hypothesis, h2: Hypothesis) -> bool:
    """h1 est-elle plus specifique que h2 ? (h1 <= h2)"""
    return is_more_general_than(h2, h1)


def generalize_for(h: Hypothesis, example: dict) -> Hypothesis:
    """Generalise h minimalement pour couvrir l'exemple positif."""
    result = list(h)
    for i, attr in enumerate(ATTRIBUTES):
        if result[i] is None or result[i] == example[attr]:
            result[i] = example[attr]
        elif result[i] != "?" and result[i] != example[attr]:
            result[i] = "?"
    return tuple(result)


def specialize_against(h: Hypothesis, example: dict) -> list[Hypothesis]:
    """Specialise h pour ne PAS couvrir l'exemple negatif.

    Retourne toutes les specialisations minimales possibles.
    """
    specializations = []
    for i, attr in enumerate(ATTRIBUTES):
        if h[i] == "?":
            # Remplacer "?" par chaque valeur possible SAUF celle de l'exemple negatif
            for val in ATTRIBUTE_VALUES[attr]:
                if val != example[attr]:
                    new_h = list(h)
                    new_h[i] = val
                    specializations.append(tuple(new_h))
    return specializations


