    delta_s = len(S_run) - s_before

    print(f"\nEx {idx:>2} [{label_str:>7}] {attrs_short}")
    print(f"  G: {g_before} -> {len(G_run)} ({delta_g:+d})  |  S: {s_before} -> {len(S_run)} ({delta_s:+d})")

