PEOPLE = ["tom", "bob", "ann", "pat", "jim", "sue"]
PARENT = [("tom", "bob"), ("bob", "ann"), ("bob", "pat"), ("pat", "jim"), ("ann", "sue")]


def transitive_closure(edges):
    """Cloture transitive de `edges` : les vrais couples ancestor(X, Y)."""
    succ = {}
    for a, b in edges:
        succ.setdefault(a, set()).add(b)
    cur = set(edges)
    while True:
        nxt = set(cur)
        for a, b in cur:
            for c in succ.get(b, ()):
                nxt.add((a, c))
        if nxt == cur:
            return cur
        cur = nxt


