def fuzzy_and(a: float, b: float) -> float:
    return a * b

def fuzzy_or(a: float, b: float) -> float:
    return a + b - a * b

def fuzzy_not(a: float) -> float:
    return 1.0 - a

def fuzzy_implies(a: float, b: float) -> float:
    return min(1.0, b / max(a, 1e-10))

